# Check if two strings are anagrams using dict
def is_anagram(s1, s2):
    freq = {}
    for ch in s1:
        freq[ch] = freq.get(ch,0) + 1
    for ch in s2:
        freq[ch] = freq.get(ch,0) - 1
    return all(v==0 for v in freq.values())
print(is_anagram('listen','silent'))

