# Timer decorator
import time

def timer(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f'Time: {end-start:.4f}s')
        return result
    return wrapper

@timer
def slow_add(a, b):
    return a + b

print(slow_add(5, 10))

